template <typename T, LLI BASE, LLI MOD> class RollingHash{

private:

  static vector<LLI> pow;



public:

  static void init(int N){

    pow.assign(N+1,0);

    pow[0] = 1;

    FORE(i,1,N){

      pow[i] = pow[i-1]*BASE % MOD;

    }

  }



  static vector<LLI> generate_hash(const T &s){

    vector<LLI> ret(s.size()+1);



    FORE(i,1,(int)s.size()){

      ret[i] = (ret[i-1]*BASE+s[i-1]) % MOD;

    }



    return ret;

  }



  static LLI hash(const vector<LLI> &shash, int i, int j){ // [i, j)

    return (shash[j] - shash[i] * pow[j-i] + MOD*MOD) % MOD;

  }



  static LLI hash(const T &p){

    LLI phash = 0;

    REP(i,(int)p.size()) phash = (phash*BASE+p[i]) % MOD;

    return phash;

  }





  static vector<int> find(const vector<LLI> &shash, const T &p){

    vector<int> ret;

    int pl = p.size();

    LLI phash = hash(p);

    REP(i,(int)shash.size()-pl) if(hash(shash,i,i+pl) == phash) ret.push_back(i);

    return ret;

  }

};



template <typename T, LLI BASE, LLI MOD> vector<LLI> RollingHash<T,BASE,MOD>::pow;



using R1 = RollingHash<string,31,1000000009>;

using R2 = RollingHash<string,41,998244353>;



int main(){

  R1::init(10000);

  R2::init(10000);



  int N;

  string s;

  while(cin >> N >> s){



    auto hs1 = R1::generate_hash(s);

    auto hs2 = R2::generate_hash(s);



    int ans = 0;



    auto check =

      [&](int L){

        set<pair<LLI,LLI>> store;

        queue<pair<LLI,LLI>> q;



        REP(i,N-L+1){

          auto h1 = R1::hash(hs1,i,i+L);

          auto h2 = R2::hash(hs2,i,i+L);



          pair<LLI,LLI> H(h1,h2);



          if(EXIST(store,H)){

            return true;

          }



          if((int)q.size() == L-1){

            q.push(H);

